// Buzzer/horn sound via Web Audio API (no external file needed)
let _audioCtx = null;
function playHorn(){
  try {
    if(!_audioCtx) _audioCtx = new (window.AudioContext||window.webkitAudioContext)();
    const ctx = _audioCtx;
    if(ctx.state==="suspended") ctx.resume();
    const now = ctx.currentTime;
    // Two-tone buzzer like a real game horn
    [0, 0.0].forEach(()=>{});
    const makeTone = (start, dur, freq) => {
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = "sawtooth";
      osc.frequency.value = freq;
      gain.gain.setValueAtTime(0, start);
      gain.gain.linearRampToValueAtTime(0.35, start+0.02);
      gain.gain.setValueAtTime(0.35, start+dur-0.05);
      gain.gain.linearRampToValueAtTime(0, start+dur);
      osc.connect(gain); gain.connect(ctx.destination);
      osc.start(start); osc.stop(start+dur);
    };
    // Long single blast
    makeTone(now, 1.4, 220);
    makeTone(now, 1.4, 277);
  } catch(e){ /* audio not available */ }
}

function standings(teamList, matches) {
  const st = {};
  teamList.forEach(t=>st[t.id]={id:t.id,name:t.name,color:t.color,W:0,L:0,PF:0,PA:0,pts:0});
  matches.forEach(m=>{
    if(!m.done) return;
    const h=parseInt(m.hs), a=parseInt(m.as);
    st[m.home].PF+=h; st[m.home].PA+=a;
    st[m.away].PF+=a; st[m.away].PA+=h;
    if(h>a){st[m.home].W++;st[m.home].pts+=2;st[m.away].L++;st[m.away].pts+=1;}
    else{st[m.away].W++;st[m.away].pts+=2;st[m.home].L++;st[m.home].pts+=1;}
  });
  return Object.values(st).sort((a,b)=>b.pts-a.pts||(b.PF-b.PA)-(a.PF-a.PA)||b.PF-a.PF);
}

